第八屆YTP國中組 2023&#x2F;7&#x2F;28記分板 題目題目 總分:100&#x2F;185 送分題helloworld30&#x2F;30 1.股市小達人(Stonks)0&#x2F;10 有n個季節，一開始Nathan用x元買入一張股票，接下來N個季節公司會將股價更新為ai，然後發股息，每張股票會收到[ai&#x2F;100]元，接下來Nathan會用它存下來的股息買盡量多的股票，再最後一季Nathan將所有股票賣出，問他賣出股票後拿到的錢+剩下的股息有沒有比買股票花的錢多。 我想我肯定誤會題目了，一開始想說很簡單給姐姐寫，她寫很久都寫不出來，結果我也找不出錯誤…!?好像是因為overflow😭😢😭 2.一起學日語(Learn Japenese)10&#x2F;10 輸入字串，5個case，再變化後輸出，詳細見題目⬆ 照他的方法直接寫就好了，所以我把這題給姊姊寫，想說給她點參與感，她寫很久，在她寫的時候我就先想其他題目。 code 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long//#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int t; string s; cin&gt;&gt;t; for(int i=0; i&lt;t; i++) &#123; cin&gt;&gt;s; if(s.substr(s.size()-2,1)!=&quot;r&quot; || s.substr(s.size()-1,1)!=&quot;u&quot;) &#123; s=s.substr(0,s.size()-1)+&quot;imasu&quot;; &#125; else &#123; if(s.substr(s.size()-3,1)==&quot;u&quot; &amp;&amp; s.substr(s.size()-4,1)==&quot;s&quot;) &#123; s=s.substr(0,s.size()-4)+&quot;simasu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;u&quot; &amp;&amp; s.substr(s.size()-4,1)==&quot;k&quot;) &#123; s=s.substr(0,s.size()-4)+&quot;kimasu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;a&quot; || s.substr(s.size()-3,1)==&quot;u&quot; || s.substr(s.size()-3,1)==&quot;o&quot;) &#123; s=s.substr(0,s.size()-1)+&quot;imasu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;i&quot;) &#123; s=s.substr(0,s.size()-2)+&quot;masu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;e&quot;) &#123; s=s.substr(0,s.size()-2)+&quot;masu&quot;; &#125; &#125; cout&lt;&lt;s&lt;&lt;&quot;
&quot;; &#125; return 0;&#125; 3.十一(Eleven)10&#x2F;10 輸出符合 1.位數加總為n2.沒有03.被11整除 最大的數沒有符合的數就輸出-1 一開始我看到這題就覺得一定很簡單，就如果n是偶數就輸出n個1，否則輸出-1，結果上傳後…0分…啊!…為啥錯了…這時姊姊告訴我奇偶位數和可能差11啊，我才想到11的倍數的定義…可能一開始太緊張了吧XD，最後找到規律：如果n是奇數，&lt;&#x3D;11的就是-1，&gt;11的就輸出913+(n-13)個1，然後就AC了。 code 1234567891011121314151617181920212223242526272829303132333435363738394041#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int n; cin&gt;&gt;n; if(n%2==1) &#123; if(n&lt;=11) cout&lt;&lt;&quot;-1
&quot;; else &#123; int a=(n-11)/2,b=n-a; cout&lt;&lt;913; REP(i,n-13) cout&lt;&lt;1; cout&lt;&lt;&quot;
&quot;; &#125; &#125; else &#123; REP(i,n) cout&lt;&lt;&quot;1&quot;; cout&lt;&lt;&quot;
&quot;; &#125; return 0;&#125; 4.路燈(Street Light)15&#x2F;15 N*M的地圖，一個在(x,y)且亮度為p的路燈會帶給(r,c)的亮度max(0,p-max(|r-x|,|c-y|))每個格子的亮度為每個路燈帶給它的亮度取最大值輸入每個格子的亮度b[i][j]，輸出那些座標有路燈和它的亮度 一開始我的想法是從盤面上最大亮度到最小看，每一次檢查(i,j)如果它最終亮度&gt;目前它的亮度，就設一個路燈亮度b[i][j]，如果&#x3D;就跳過，如果&lt;就代表不合理，輸出-1 O((nm)^2^)會TLE。之後一段時間都沒什麼想法，所以我就先做第5題，再回來看突然發現每一格的周圍八格一定&gt;&#x3D;它的亮度-1，否則無解，可以簡單證明其他狀況有解(或靠第六感)，而我還發現他不需要最小化路燈的數量，在亮度為p的路燈周圍設亮度為p-1的路燈有設和沒設是一樣的，所以我就把所有會亮的地方都設了路燈，路燈亮度就是這格的最終亮度b[i][j] O(mn)我想現實生活中這樣設路燈是智障才會做的是…XXXXD(啊不是很有錢!!XD) 不過其實我忘記檢查斜線了(我只檢查周圍4格)，他可能測資比較弱所以還是AC了。 code 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int n,m; cin&gt;&gt;n&gt;&gt;m; vector&lt;vector&lt;int&gt;&gt; a(n,vector&lt;int&gt;(m)); vector&lt;pair&lt;pii,int&gt;&gt; an; REP(i,n) &#123; REP(j,m) &#123; cin&gt;&gt;a[i][j]; if(a[i][j]&gt;0) an.pb(&#123;&#123;i+1,j+1&#125;,a[i][j]&#125;); &#125; &#125; bool ok=1; REP(i,n-1) &#123; REP(j,n) &#123; if(a[i][j]&lt;a[i+1][j]-1||a[i+1][j]&lt;a[i][j]-1) &#123; ok=0; break; &#125; &#125; &#125; REP(i,n) &#123; REP(j,n-1) &#123; if(a[i][j]&lt;a[i][j+1]-1||a[i][j+1]&lt;a[i][j]-1) &#123; ok=0; break; &#125; &#125; &#125; if(ok) &#123; cout&lt;&lt;an.size()&lt;&lt;&quot;
&quot;; REP(i,an.size()) &#123; cout&lt;&lt;an[i].f.f&lt;&lt;&quot; &quot;&lt;&lt;an[i].f.s&lt;&lt;&quot; &quot;&lt;&lt;an[i].s&lt;&lt;&quot;
&quot;; &#125; &#125; else cout&lt;&lt;&quot;-1
&quot;; return 0;&#125; 5.遊戲體力值(Game Stamina)15&#x2F;15 小Y在第kt+r(t&gt;&#x3D;0且t∈Z)分鐘時體力值會加一，小Y查詢體力值n次，第i次是在ti分鐘，且體力值為si(1&lt;&#x3D;i&lt;&#x3D;n)，且t1&lt;t2&lt;…&lt;tn，每次查詢輸出長度為k的01字串p0p1…pk-1，pj&#x3D;1代表r可能是j，&#x3D;0代表r不可能是j 如果第t分鐘的體力值為p，則第t-k分鐘的體力值為p-1，可以知道第t-pk分鐘的體力值為0，再找目前ti-kpi的最小值與最大值分別為mn、mx，再輸出[(k-mx),mn]%k為1，其他為0 code 12345678910111213141516171819202122232425262728293031323334353637383940414243#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int n,k; cin&gt;&gt;n&gt;&gt;k; int mn=inf,mx=-inf; REP(i,n) &#123; int t,s; cin&gt;&gt;t&gt;&gt;s; int r=t-s*k; mn=min(mn,r); mx=max(mx,r); vector&lt;int&gt; an(k); REP(j,k-(mx-mn)) &#123; int x=mn-j; an[(x%k+k)%k]=1; &#125; REP(j,k) cout&lt;&lt;an[j]; cout&lt;&lt;&quot;
&quot;; &#125; return 0;&#125; 6.漆彈遊戲(Paintball Game)15&#x2F;15 在n*n的盤面上，有m人在玩遊戲，從1號到m號，每個人可以選一個格子(x,y)放一顆威力為li且顏色為i的漆彈(1&lt;&#x3D;i&lt;&#x3D;m，li為奇數)，漆彈的爆炸範圍為以(x,y)做為中心且寬度為li的十字( min(|x’-x|,|y’-y|)&lt;&#x3D;(li-1)&#x2F;2 )，可以覆蓋本來的顏色，每一回合結束竹子就會查詢(a,b)和(c,d)所形成的區域中顏色pi的數量 我的想法是記錄每一行每一列最後一個染色的顏色，每一次查詢是pi ai bi ci dia1&#x3D;[b,d]這些column中有幾個顏色&#x3D;pa2&#x3D;[b,d]這些column中有幾個顏色&gt;p(被覆蓋)b1&#x3D;[a,c]這些row中有幾個顏色&#x3D;pb2&#x3D;[a,c]這些row中有幾個顏色&gt;p(被覆蓋)而答案就是(d-b+1-a2)b1+a1(c-a+1-b2)-a1*b1O(nm) code 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int n,m; cin&gt;&gt;n&gt;&gt;m; vector&lt;int&gt; r(n),c(n); REP(i,m) &#123; int l,x,y; cin&gt;&gt;l&gt;&gt;x&gt;&gt;y; x--,y--; r[x]=i+1; REP1(j,(l-1)/2) &#123; if(x+j&lt;n) r[x+j]=i+1; if(x-j&gt;=0) r[x-j]=i+1; &#125; c[y]=i+1; REP1(j,(l-1)/2) &#123; if(y+j&lt;n) c[y+j]=i+1; if(y-j&gt;=0) c[y-j]=i+1; &#125; int p,a,b,c2,d; cin&gt;&gt;p&gt;&gt;a&gt;&gt;b&gt;&gt;c2&gt;&gt;d; a--,b--,c2--,d--; int an=0,a1=0,a2=0,b1=0,b2=0; for(int j=b;j&lt;=d;j++) &#123; if(c[j]&gt;0&amp;&amp;c[j]!=p&amp;&amp;c[j]&gt;p) a2++; if(c[j]==p) a1++; &#125; for(int j=a;j&lt;=c2;j++) &#123; if(r[j]&gt;0&amp;&amp;r[j]!=p&amp;&amp;r[j]&gt;p) b2++; if(r[j]==p) b1++; &#125; an=(d-b+1-a2)*b1+a1*(c2-a+1-b2)-a1*b1; cout&lt;&lt;an&lt;&lt;&quot;
&quot;; &#125; return 0;&#125; 7.收費站模擬器(Toll Plaza Simulator)0&#x2F;15 有n個收費站，每天都有一段[l,r]的收費站壞掉or正常，之後每一個收費站剛好有一台車來，每台車對應到的收費站如果壞了，他就會移動到離他最近的收費站，而混亂程度就是每台車要移動的距離的總和Σ|x-x’|，每天結束後輸出目前的混亂程度。 來不及寫…😭😢😭想法就是開一棵segment tree，支持區間改值，0代表正常，1代表壞了，然後做一個f(x)來用數學算混亂程度(連續x個壞掉(兩端正常)會讓混亂程度多多少)。 code (改) #include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e6+5;const int mod=1e9+9;int f(int x) &#123; if(x%2==0) return x*x/4+x/2; else return f(x-1)+(x+1)/2;&#125;struct seg &#123; int l,r; int v,p,s; bool a; int t;&#125;;vector&lt;seg&gt; s(maxn*4);void pull(seg &amp;a,seg &amp;b,seg &amp;c) &#123;//a=b+c; if(b.a) &#123; if(c.a) &#123; a.v=0; a.p=0; a.s=0; a.a=1; &#125; else &#123; a.v=c.v; a.p=b.r-b.l+1+c.p; a.s=c.s; a.a=0; &#125; &#125; else &#123; if(c.a) &#123; a.v=b.v; a.p=b.p; a.s=b.s+c.r-c.l+1; a.a=0; &#125; else &#123; a.v=b.v+c.v+f(b.s+c.p); a.p=b.p; a.s=c.s; a.a=0; &#125; &#125;&#125;void push(seg &amp;a,seg &amp;b,seg &amp;c) &#123; if(a.t!=-1) &#123; if(a.t==0) &#123; b.v=0; b.p=0; b.s=0; b.a=0; b.t=a.t; c.v=0; c.p=0; c.s=0; c.a=0; c.t=a.t; &#125; else &#123; b.v=0; b.p=0; b.s=0; b.a=1; b.t=a.t; c.v=0; c.p=0; c.s=0; c.a=1; c.t=a.t; &#125; a.t=-1; &#125;&#125;void build(int w,int l,int r) &#123; s[w]=&#123;l,r,0,0,0,0,-1&#125;; if(l==r) return; int m=(l+r)/2; build(w*2,l,m); build(w*2+1,m+1,r);&#125;void ud(int w,int ul,int ur,int v) &#123; if(ul&lt;=s[w].l&amp;&amp;s[w].r&lt;=ur) &#123; if(v==0) &#123; s[w].v=0; s[w].p=0; s[w].s=0; s[w].a=0; s[w].t=0; &#125; if(v==1) &#123; s[w].v=0; s[w].p=0; s[w].s=0; s[w].a=1; s[w].t=1; &#125; return; &#125; if(ul&gt;s[w].r||ur&lt;s[w].l) return; int m=(s[w].l+s[w].r)/2; push(s[w],s[w*2],s[w*2+1]); ud(w*2,ul,ur,v); ud(w*2+1,ul,ur,v); pull(s[w],s[w*2],s[w*2+1]);&#125;int qu() &#123; return s[1].v;&#125;signed main()&#123; IOS(); int n,q; cin&gt;&gt;n&gt;&gt;q; build(1,0,n-1); REP(i,q) &#123; int x,y,z; cin&gt;&gt;x&gt;&gt;y&gt;&gt;z; y--,z--; ud(1,y,z,x%2); cout&lt;&lt;qu()&lt;&lt;&quot;
